def lcs_str(a, b):
    # returns one LCS string (not all)
    n, m = len(a), len(b)
    dp = [[0]*(m+1) for _ in range(n+1)]
    for i in range(n-1, -1, -1):
        for j in range(m-1, -1, -1):
            if a[i] == b[j]:
                dp[i][j] = dp[i+1][j+1] + 1
            else:
                dp[i][j] = max(dp[i+1][j], dp[i][j+1])
    # reconstruct
    i, j = 0, 0
    res = []
    while i < n and j < m:
        if a[i] == b[j]:
            res.append(a[i])
            i += 1
            j += 1
        else:
            if dp[i+1][j] >= dp[i][j+1]:
                i += 1
            else:
                j += 1
    return ''.join(res)

